        "viz_xrHwbs2d": {
            "type": "splunk.events",
            "dataSources": {
                "primary": "ds_VeMAoTc7"
            },
            "containerOptions": {
                "visibility": {
                    "hideWhenNoData": true
                }
            }
        }
    },
    "dataSources": {
        "ds_0SMt5AlB": {
            "name": "Event Type - Drilldown",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\"\n| search account_name IN ($account_name$)\n| search Event = $first_row_event_type$\n| eval browser=case(\n    match(user_agent, \"Chrome\"), \"Chrome\",\n    match(user_agent, \"Firefox\"), \"Firefox\",\n    match(user_agent, \"Safari\") AND NOT match(user_agent, \"Chrome\"), \"Safari\",\n    match(user_agent, \"Edge\"), \"Edge\",\n    match(user_agent, \"MSIE|Trident\"), \"Internet Explorer\",\n    match(user_agent, \"curl|http|python-requests\"), \"Scripted Client\",\n    1==1, \"Other\"\n)\n\n| eval keep = case(\n    \"$clicked_first_row$\"=\"event_type\" AND Event = \"$event_type$\", 1,\n    \"$clicked_first_row$\"=\"browser_usage\" AND browser = \"$browser_usage$\" AND browser != \"Other\", 1,\n    true(), 0\n)\n| where keep=1\n\n| eval OperationStatus = case(\n    HttpResponseCode == 0, \"Other\",\n    like(tostring(HttpResponseCode), \"2%\"), \"Success\",\n    true(), \"Failed\"\n)\n| eval MoDisplayName='MoDisplayNames.Name{}'\n| eval RequestScheduledActions='Request.ScheduledActions{}.Action'\n| eval ScheduledActions='HttpResponsePayload.ScheduledActions{}.Action'\n| eval Request_Actions='Request.Actions{}.ObjectType'\n| rename browser as Browser\n| eval ObjectName=coalesce(HttpResponsePayload.Name, MoDisplayName)\n| eval ActionTaken=coalesce('Request.Action', 'Request_Actions', 'Request.AdminAction', 'Request.AdminLocatorLedAction', 'Request.ResetAction.Action', 'Request.VethAction', 'Request.VfcAction', 'Request.Acknowledge', 'RequestScheduledActions', 'HttpResponsePayload.Action', 'HttpResponsePayload.AdminAction', 'HttpResponsePayload.VethAction', 'HttpResponsePayload.VfcAction', 'HttpResponsePayload.Input.Action', 'ScheduledActions', 'HttpResponsePayload.UplinkFailAction', 'HttpResponsePayload.ConfigContext.ConfigState', if(isnotnull(HttpResponsePayload.Description), HttpResponsePayload.Description, Event))\n| rename Moid as _moid, account_name as AccountName\n| table AccountName, _moid, Browser, UserIdOrEmail, Event, HttpOperation, OperationStatus, ObjectName, MoType, ActionTaken, TraceId\n| sort AccountName",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_1IFE5xno": {
            "name": "User Login Activity Overview",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\" Event=\"Login\"\n| search account_name IN ($account_name$)\n| search UserIdOrEmail IN ($user_name$)\n| dedup Moid\n| stats \n    count as \"Login Count\",\n    dc(SourceIp) as \"Unique Ips\",\n    values(SourceIp) as \"Source Ips\",\n    earliest(_time) as first_login,\n    latest(_time) as last_login,\n    by UserIdOrEmail, account_name\n| rename UserIdOrEmail as User, account_name as \"Account Name\"\n| eval first_login = strftime(tonumber(first_login), \"%Y-%m-%d %H:%M:%S\"),\n      last_login  = strftime(tonumber(last_login), \"%Y-%m-%d %H:%M:%S\")\n| rename first_login as \"First Login\", last_login as \"Recent Login\"\n| sort -login_count",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_2887e0lB": {
            "name": "Server Profile _Raw Event",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\"\n| search Moid=$server_profile_moid$",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_3C38UlTM": {
            "name": "Assign Server Profile",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\" Event=\"Created\" \"POST /v1/server/Profiles\" Request.WorkflowNameSuffix != \"\"\n| search account_name IN ($account_name$)\n| search UserIdOrEmail IN ($user_name$)\n| dedup Moid\n| rename Request.Targets{}.AssignedServer.Moid as assigned_server_moid,\tRequest.Targets{}.ServerAssignmentMode as \"Server Assignment Mode\", Request.Targets{}.Name as \"Server Profile Name\", Request.Targets{}.Description as \"Server Profile Description\", Moid as _moid\n| join type=left assigned_server_moid [ | inputlookup cisco_intersight_compute_physicalsummaries | where splunk_managed_lifecycle == \"PRESENT\" | rename Moid as assigned_server_moid, Name as \"Server Name\" ]\n| table \"Server Assignment Mode\", \"Server Profile Name\", \"Server Profile Description\", \"Server Name\", Model, TraceId, _moid",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_7ezOBalU": {
            "name": "Event Type",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\"\n| search account_name IN ($account_name$)\n| search UserIdOrEmail IN ($user_name$)\n| dedup Moid\n| stats count by Event",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_93aAcBt9": {
            "name": "Account Name Filter",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\"\n| dedup account_name\n| table account_name",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_9gmohVTu": {
            "name": "Geographic Analysis of Login Activity",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\" Event=\"Login\"\n| search account_name IN ($account_name$)\n| search UserIdOrEmail IN ($user_name$)\n| dedup Moid\n| iplocation SourceIp\n| eval full_city = City . \", \" . Country\n| geostats latfield=lat longfield=lon count by full_city",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_AqM14o65": {
            "name": "Server Power State Changes",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\" HttpOperation=\"*POST /api/v1/compute/ServerSettings/*\" HttpResponsePayload.AdminPowerState IN (\"PowerOn\",\"PowerOff\")\n| search account_name IN ($account_name$)\n| search UserIdOrEmail IN ($user_name$)\n| dedup Moid\n| rename HttpResponsePayload.Ancestors{}.Moid as ancestors_moid, HttpResponsePayload.Ancestors{}.ObjectType as \"Server Type\", UserIdOrEmail as \"User\", HttpResponsePayload.AdminPowerState as \"Power State\", Moid as _moid\n| join type=left ancestors_moid [ | inputlookup cisco_intersight_compute_physicalsummaries | where splunk_managed_lifecycle == \"PRESENT\" | rename Moid as ancestors_moid ]\n| eval MoDisplayNames_Name = 'MoDisplayNames.Name{}'\n| eval Name=coalesce(Name,MoDisplayNames_Name)\n| eval \"Server Type\"=coalesce('Server Type', MoType)\n| table User, Name, \"Server Type\", Event, \"Power State\", ModTime, TraceId, _moid",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_E9WeSnPx": {
            "name": "Permission Change _Raw event",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\"\n| search Moid = \"$permission_change_moid$\"",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_GMh5gbjd": {
            "name": "Hardware Commissioning Status",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\" HttpOperation=\"*POST*\" HttpResponsePayload.AdminAction != \"\"\n| search account_name IN ($account_name$)\n| search UserIdOrEmail IN ($user_name$)\n| dedup Moid\n| rename HttpResponsePayload.Moid as ancestors_moid, UserIdOrEmail as \"User\", HttpResponsePayload.AdminAction as \"Server State\", HttpResponsePayload.AdminActionState as \"Server Action State\", HttpResponsePayload.Lifecycle as Lifecycle, Moid as _moid\n| join type=left ancestors_moid [\n    | inputlookup cisco_intersight_compute_rackunitidentities | where splunk_managed_lifecycle == \"PRESENT\" | rename Moid as ancestors_moid\n    | append [| inputlookup cisco_intersight_compute_bladeidentities | where splunk_managed_lifecycle == \"PRESENT\" | rename Moid as ancestors_moid ]\n    | append [| inputlookup cisco_intersight_equipment_chassisidentities | where splunk_managed_lifecycle == \"PRESENT\" | rename Moid as ancestors_moid ]\n    | append [| inputlookup cisco_intersight_fabric_elementidentities | where splunk_managed_lifecycle == \"PRESENT\" | rename Moid as ancestors_moid ]\n]\n| eval MoDisplayNames_Name = 'MoDisplayNames.Name{}'\n| eval Name=coalesce(Name,MoDisplayNames_Name)\n| eval \"Server Action State\"=coalesce('Server Action State', 'Request.AdminAction')\n| table User, Name, Event, \"Server State\", \"Server Action State\", Lifecycle, ModTime, TraceId, _moid",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_NG8vCmPM": {
            "name": "What Permission Change",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\" Event=\"Permission Change\"\n| search account_name IN ($account_name$)\n| search UserIdOrEmail IN ($user_name$)\n| dedup Moid\n| rename Request.OldPermissionNames{} as \"Previous Roles & Permissions\", Request.PermissionNames{} as \"Current Roles & Permissions\", ModTime as \"Last Updated\", account_name as \"Account Name\", UserIdOrEmail as \"Changed By\", Request.UserIdOrEmail as \"Changed User\", Moid as \"_moid\"\n| table \"Changed By\", \"Last Updated\", \"Account Name\", \"Previous Roles & Permissions\", \"Changed User\", \"Current Roles & Permissions\", TraceId, _moid",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_PjWmfSss": {
            "name": "Top Countries by User",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\" Event=\"Login\"\n| search account_name IN ($account_name$)\n| search UserIdOrEmail IN ($user_name$)\n| dedup Moid\n| iplocation SourceIp\n| top Country",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_e17teKSt": {
            "name": "User Name Filter",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\"\n| dedup UserIdOrEmail\n| table UserIdOrEmail",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_hvOu5B4d": {
            "name": "Top Countries by User - Drilldown",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\"\n| search account_name IN ($account_name$)\n| search Event = $second_row_event_type$\n| iplocation SourceIp\n\n| eval keep = case(\n    \"$clicked_second_row$\"=\"geography\" AND Country = \"$countries_by_user$\" AND Event=\"Login\", 1,\n    \"$clicked_second_row$\"=\"top_users\" AND UserIdOrEmail = \"$top_users$\", 1,\n    true(), 0\n)\n| where keep=1\n\n| eval OperationStatus = case(\n    HttpResponseCode == 0, \"Other\",\n    like(tostring(HttpResponseCode), \"2%\"), \"Success\",\n    true(), \"Failed\"\n)\n| eval MoDisplayName='MoDisplayNames.Name{}'\n| eval RequestScheduledActions='Request.ScheduledActions{}.Action'\n| eval ScheduledActions='HttpResponsePayload.ScheduledActions{}.Action'\n| eval Request_Actions='Request.Actions{}.ObjectType'\n| rename browser as Browser\n| eval ObjectName=coalesce(HttpResponsePayload.Name, MoDisplayName)\n| eval ActionTaken=coalesce('Request.Action', 'Request_Actions', 'Request.AdminAction', 'Request.AdminLocatorLedAction', 'Request.ResetAction.Action', 'Request.VethAction', 'Request.VfcAction', 'Request.Acknowledge', 'RequestScheduledActions', 'HttpResponsePayload.Action', 'HttpResponsePayload.AdminAction', 'HttpResponsePayload.VethAction', 'HttpResponsePayload.VfcAction', 'HttpResponsePayload.Input.Action', 'ScheduledActions', 'HttpResponsePayload.UplinkFailAction', 'HttpResponsePayload.ConfigContext.ConfigState', if(isnotnull(HttpResponsePayload.Description), HttpResponsePayload.Description, Event))\n| rename Moid as _moid, account_name as AccountName\n| table AccountName, Country, UserIdOrEmail, _moid, Event, HttpOperation, OperationStatus, ObjectName, MoType, ActionTaken, TraceId\n| sort AccountName",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_jZgKDMex": {
            "name": "Active Session at a Time",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\" (Event=\"Login\" OR Event=\"Logout\")\n| search account_name IN ($account_name$)\n| search UserIdOrEmail IN ($user_name$)\n| dedup Moid\n| sort UserIdOrEmail, _time\n| streamstats \n    sum(eval(if(Event=\"Login\", 1, 0))) as cumulative_logins,\n    sum(eval(if(Event=\"Logout\", 1, 0))) as cumulative_logouts\n    by UserIdOrEmail\n| eval active_sessions=cumulative_logins-cumulative_logouts\n| timechart \n    span=15m \n    max(active_sessions) as \"Peak Active Sessions\"",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_kAxmHNst": {
            "name": "Top Users",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\" \n| search account_name IN ($account_name$)\n| search UserIdOrEmail IN ($user_name$)\n| dedup Moid\n| stats count by UserIdOrEmail",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_l0bs2LP7": {
            "name": "Browser Usage by User",
            "options": {
                "query": "`cisco_intersight_index` source=aaaAuditRecord\n| dedup Moid\n| eval browser=case(\n    match(user_agent, \"Chrome\"), \"Chrome\",\n    match(user_agent, \"Firefox\"), \"Firefox\",\n    match(user_agent, \"Safari\") AND NOT match(user_agent, \"Chrome\"), \"Safari\",\n    match(user_agent, \"Edge\"), \"Edge\",\n    match(user_agent, \"MSIE|Trident\"), \"Internet Explorer\",\n    match(user_agent, \"curl|http|python-requests\"), \"Scripted Client\",\n    1==1, \"Other\"\n)\n| where browser != \"Other\"\n| search account_name IN ($account_name$)\n| search UserIdOrEmail IN ($user_name$)\n| stats count by browser",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_t2upmzo5": {
            "name": "Hardware Commissioning State _Raw Event",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\"\n| search Moid=$hardware_commission_moid$",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_vNQgGWmX": {
            "name": "User-Specific Timeline",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\" (Event=\"Login\" OR Event=\"Logout\")\n| search account_name IN ($account_name$)\n| search UserIdOrEmail IN ($UserIdOrEmail$)\n| timechart span=1m\n    count(eval(Event=\"Login\")) as Logins,\n    count(eval(Event=\"Logout\")) as Logouts\n    by UserIdOrEmail",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_vVJszi5T": {
            "name": "Server Power State _Raw Event",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\"\n| search Moid=$server_power_state_moid$",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_woLhfWSn": {
            "name": "Login vs Logout vs Active Users Timeline",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\" (Event=\"Login\" OR Event=\"Logout\")\n| search account_name IN ($account_name$)\n| search UserIdOrEmail IN ($user_name$)\n| dedup Moid\n| bucket _time\n| stats \n    count(eval(Event=\"Login\")) as Logins,\n    count(eval(Event=\"Logout\")) as Logouts\n    by _time\n| eval Net_Active_Users=Logins-Logouts\n| fields _time, Logins, Logouts, Net_Active_Users",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "type": "ds.search"
        },
        "ds_gz8ntMSl": {
            "type": "ds.search",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\"\n| search account_name = $account_name$\n\n| eval browser=case(\n    match(user_agent, \"Chrome\"), \"Chrome\",\n    match(user_agent, \"Firefox\"), \"Firefox\",\n    match(user_agent, \"Safari\") AND NOT match(user_agent, \"Chrome\"), \"Safari\",\n    match(user_agent, \"Edge\"), \"Edge\",\n    match(user_agent, \"MSIE|Trident\"), \"Internet Explorer\",\n    match(user_agent, \"curl|http|python-requests\"), \"Scripted Client\",\n    1==1, \"Other\"\n)\n\n| eval keep = case(\n    \"$clicked_first_row$\"=\"event_type\" AND Event = \"$event_type$\", 1,\n    \"$clicked_first_row$\"=\"browser_usage\" AND browser = \"$browser_usage$\" AND browser != \"Other\", 1,\n    true(), 0\n)\n| where keep=1\n\n| table Event",
                "queryParameters": {
                    "earliest": "$global_time.earliest$",
                    "latest": "$global_time.latest$"
                }
            },
            "name": "Event Type dropdown first row"
        },
        "ds_SSabdHpS_ds_gz8ntMSl": {
            "type": "ds.search",
            "options": {
                "query": "`cisco_intersight_index` source=\"aaaAuditRecord\"\n| search account_name = $account_name$\n| iplocation SourceIp\n\n| eval keep = case(\n    \"$clicked_second_row$\"=\"geography\" AND Country = \"$countries_by_user$\" AND Event=\"Login\", 1,\n    \"$clicked_second_row$\"=\"top_users\" AND UserIdOrEmail = \"$top_users$\", 1,\n    true(), 0\n)\n| where keep=1\n\n| table Event",
                "queryParameters": {
